```dart
class CleanApp extends StatefulWidget {
  const CleanApp({super.key});
  @override
  State<CleanApp> createState() => _CleanAppState();
}

class _CleanAppState extends State<CleanApp> {
  AppThemeMode _themeMode = AppThemeMode.system;
  int _currentIndex = 0;

  void _toggleTheme() {
    setState(() {
      _themeMode = switch (_themeMode) {
        AppThemeMode.system => AppThemeMode.light,
        AppThemeMode.light => AppThemeMode.dark,
        AppThemeMode.dark => AppThemeMode.system,
      };
    });
  }

  ThemeMode get _resolvedThemeMode => switch (_themeMode) {
    AppThemeMode.light => ThemeMode.light,
    AppThemeMode.dark => ThemeMode.dark,
    AppThemeMode.system => ThemeMode.system,
  };

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: "CleanApp",
      debugShowCheckedModeBanner: false,
      theme: AppTheme.lightTheme,
      darkTheme: AppTheme.darkTheme,
      themeMode: _resolvedThemeMode,
      home: Scaffold(
        appBar: AppBar(
          title: const Text("CleanApp"),
          actions: [
            IconButton(
              icon: Icon(_themeModeIcon),
              onPressed: _toggleTheme,
              tooltip: "Cambiar tema",
            ),
          ],
        ),
        body: _screens[_currentIndex],
        bottomNavigationBar: NavigationBar(
          selectedIndex: _currentIndex,
          onDestinationSelected: (index) => setState(() => _currentIndex = index),
          destinations: const [
            NavigationDestination(icon: Icon(Icons.home_outlined), selectedIcon: Icon(Icons.home), label: "Inicio"),
            NavigationDestination(icon: Icon(Icons.checklist_outlined), selectedIcon: Icon(Icons.checklist), label: "Actividades"),
            NavigationDestination(icon: Icon(Icons.calendar_month_outlined), selectedIcon: Icon(Icons.calendar_month), label: "Calendario"),
          ],
        ),
      ),
    );
  }
}
```

