/// Sample anonymous comments for the current week schedule.
/// Returns comments that were "sent" to the person responsible this week.
static List<Comment> get commentsForCurrentSchedule {
  final currentSchedule = _currentWeekSchedule;
  if (currentSchedule == null) return [];
  return [
    Comment(
      id: "c1",
      scheduleId: currentSchedule.id,
      message: "Recuerda limpiar bien detrás del retrete, la última vez quedó sucio.",
      createdAt: DateTime.now().subtract(const Duration(hours: 5)),
    ),
    Comment(
      id: "c2",
      scheduleId: currentSchedule.id,
      message: "Por favor no olvides sacar la basura del bote pequeño también.",
      createdAt: DateTime.now().subtract(const Duration(hours: 2)),
    ),
    Comment(
      id: "c3",
      scheduleId: currentSchedule.id,
      message: "¡Gracias por mantener limpio el baño! Se aprecia mucho.",
      createdAt: DateTime.now().subtract(const Duration(minutes: 30)),
    ),
  ];
}

/// Helper: find the schedule for the current week, or null.
static CleaningSchedule? get _currentWeekSchedule {
  final now = DateTime.now();
  final currentMonday = now.subtract(Duration(days: now.weekday - 1));
  final weekStart = DateTime(currentMonday.year, currentMonday.month, currentMonday.day);
  final weekEnd = weekStart.add(const Duration(days: 7));
  try {
    return schedules.firstWhere(
      (s) => !s.date.isBefore(weekStart) && s.date.isBefore(weekEnd),
    );
  } catch (_) {
    return null;
  }
}

/// The user responsible for cleaning this week, or null.
static UserModel? get currentWeekResponsible {
  final schedule = _currentWeekSchedule;
  if (schedule == null) return null;
  try {
    return users.firstWhere((u) => u.id == schedule.userId);
  } catch (_) {
    return null;
  }
}
```

### Important:
- The `_currentWeekSchedule` helper uses the same Monday-calculation logic already in the `schedules` getter.
- `commentsForCurrentSchedule` always returns 3 sample comments regardless of who the responsible user is.
- `currentWeekResponsible` returns the UserModel of whoever is assigned this week.
- Use `try/catch` around `firstWhere` to handle the case where no match is found (return null).

