## What to do
Create a service class that wraps all Supabase database operations, replacing MockData as the data source.

### Class: `SupabaseService`
```dart
import "package:flutter_cleanapp/core/supabase_config.dart";
import "package:flutter_cleanapp/models/user_model.dart";
import "package:flutter_cleanapp/models/cleaning_schedule.dart";
import "package:flutter_cleanapp/models/cleaning_task.dart";
import "package:flutter_cleanapp/models/comment.dart";

class SupabaseService {
  SupabaseService._();
  static final SupabaseService instance = SupabaseService._();

  // --- Auth helpers ---

  /// Current authenticated user profile, or null.
  Future<UserModel?> getCurrentUser() async {
    final authUser = SupabaseConfig.client.auth.currentUser;
    if (authUser == null) return null;
    final data = await SupabaseConfig.client
        .from("profiles")
        .select()
        .eq("id", authUser.id)
        .single();
    return UserModel.fromJson(data);
  }

  // --- Profiles ---

  Future<List<UserModel>> getUsers() async {
